INSERT INTO tb_work_recode
    (
     work_proc_id
   , item_cd
   , work_date
   , work_start_time
   , work_end_time
   , worker_cnt
   , use_Qty
   , prod_Qty
   , reg_id
   , upd_id
    )
VALUES (
         #{workProcId}
       , #{itemCd}
       , #{workDate}
       , #{workStartTime}
       , #{workEndTime}
       , #{workerCnt}
       , #{useQty}
       , #{prodQty}
       , #{userId}
       , #{userId}
       )

mapper.update:
UPDATE tb_work_recode
SET work_proc_id     = #{workProcId}
  , item_cd          = #{itemCd}
  , work_date        = #{workDate}
  , work_start_time  = #{workStartTime}
  , work_end_time    = #{workEndTime}
  , worker_cnt       = #{workerCnt}
  , matUseQty        = #{matUseQty}
  , coatingQty       = #{coatingQty}
  , upd_id           = #{updId}
  , upd_dt           = GETDATE()
WHERE work_recode_id = #{workRecodeId}
